import{_ as t,o,c as a,ag as r}from"./chunks/framework._658-eYr.js";const i="/CRAFT/assets/voice-picker.DU9SPjHd.png",p=JSON.parse('{"title":"Settings","description":"","frontmatter":{},"headers":[],"relativePath":"guide/settings.md","filePath":"guide/settings.md"}'),n={name:"guide/settings.md"};function s(l,e,c,d,g,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h1><p>Access channel settings by clicking the <strong>gear icon</strong> on a channel in the sidebar.</p><h2 id="character" tabindex="-1">Character <a class="header-anchor" href="#character" aria-label="Permalink to &quot;Character&quot;">​</a></h2><h3 id="name-description" tabindex="-1">Name &amp; Description <a class="header-anchor" href="#name-description" aria-label="Permalink to &quot;Name &amp; Description&quot;">​</a></h3><p>Your character&#39;s name and personality description. The description is fed to the AI for all content generation — it shapes the tone, humor style, and voice of generated scripts and ideas.</p><h3 id="ai-character-creator" tabindex="-1">AI Character Creator <a class="header-anchor" href="#ai-character-creator" aria-label="Permalink to &quot;AI Character Creator&quot;">​</a></h3><p>Click <strong>Create Character</strong> to have AI generate a full personality description from a few inputs:</p><ul><li><strong>Tone</strong> — e.g., sarcastic, educational, energetic</li><li><strong>Audience</strong> — e.g., developers, gamers, students</li><li><strong>Inspiration</strong> — e.g., &quot;like if Linus Tech Tips and John Oliver had a baby&quot;</li><li><strong>Quirks</strong> — e.g., &quot;always makes food analogies&quot;, &quot;references Lord of the Rings&quot;</li></ul><h3 id="topics" tabindex="-1">Topics <a class="header-anchor" href="#topics" aria-label="Permalink to &quot;Topics&quot;">​</a></h3><p>Content themes for your channel (e.g., &quot;cloud computing&quot;, &quot;DevOps&quot;, &quot;terraform&quot;). These are used as default search hints in Discover and help the AI stay on-topic.</p><h2 id="voice" tabindex="-1">Voice <a class="header-anchor" href="#voice" aria-label="Permalink to &quot;Voice&quot;">​</a></h2><p>Configure the default TTS voice for audio generation:</p><ol><li>Select a <strong>Service</strong> — Edge TTS (free), ElevenLabs, OpenAI, OpenedAI Speech (local GPU), or RVC Voice Clone</li><li>Filter by <strong>Language</strong> and <strong>Gender</strong></li><li>Select a <strong>Voice</strong></li><li>Click <strong>Test</strong> to hear a preview</li></ol><p><img src="'+i+'" alt="Voice Picker"></p><p>The selected voice pre-populates when creating new audio projects.</p><h3 id="rvc-voice-clone" tabindex="-1">RVC Voice Clone <a class="header-anchor" href="#rvc-voice-clone" aria-label="Permalink to &quot;RVC Voice Clone&quot;">​</a></h3><p>When you select <strong>RVC Voice Clone (Edge TTS + RVC)</strong> as the service:</p><ol><li>Choose a <strong>Carrier Voice</strong> from Edge TTS — this determines pacing and inflection</li><li>Select an <strong>RVC Voice Model</strong> — your trained/downloaded model from Audio &gt; Train Voice</li><li>Save — new audio projects will use the two-stage pipeline (Edge TTS → RVC conversion)</li></ol><p>If no RVC models are installed, you&#39;ll see a prompt to visit <strong>Audio &gt; Train Voice</strong> where you can:</p><ul><li><strong>Search HuggingFace</strong> for community voice models and install with one click</li><li><strong>Upload</strong> your own trained <code>.pth</code> model files</li><li><strong>Browse</strong> <a href="https://voice-models.com/" target="_blank" rel="noreferrer">voice-models.com</a> for the largest community catalog</li></ul><h2 id="analytics-rpm" tabindex="-1">Analytics (RPM) <a class="header-anchor" href="#analytics-rpm" aria-label="Permalink to &quot;Analytics (RPM)&quot;">​</a></h2><p>Revenue Per Mille ($ per 1,000 views) is used for earnings estimates in the <a href="/CRAFT/guide/discover.html">Discover</a> channel deep dive.</p><ul><li><strong>Default</strong>: $4/1000 views</li><li><strong>Niche Presets</strong>: quick-select chips — Gaming $3, Tech $6, Finance $10, Health $8, etc.</li><li>Adjust based on your actual YouTube analytics</li></ul><h2 id="ai-context-claude-md" tabindex="-1">AI Context (CLAUDE.md) <a class="header-anchor" href="#ai-context-claude-md" aria-label="Permalink to &quot;AI Context (CLAUDE.md)&quot;">​</a></h2><p>The CLAUDE.md editor manages the context document used when Claude processes AI requests:</p><ul><li><strong>Character mode</strong> — auto-generated from your character name, description, topics, and style rules</li><li><strong>Raw mode</strong> — fully custom instructions</li></ul><p>Click <strong>Regenerate from Character</strong> to rebuild from your current settings, or edit manually and <strong>Save</strong>.</p><h2 id="color-schemes" tabindex="-1">Color Schemes <a class="header-anchor" href="#color-schemes" aria-label="Permalink to &quot;Color Schemes&quot;">​</a></h2><p>Click the <strong>palette icon</strong> in the sidebar footer to choose from 7 color schemes:</p><ul><li><strong>Classic</strong> — teal accent (default)</li><li><strong>Purple</strong> — violet accent with purple-tinted surfaces</li><li><strong>Blue</strong> — blue accent</li><li><strong>Amber</strong> — warm amber accent</li><li><strong>Rose</strong> — rose/pink accent</li><li><strong>Liquid Gold</strong> — golden amber accent</li><li><strong>Otter</strong> — warm brown with kelp-green accents</li></ul><p>Dark/light mode toggle is available inside the same palette popup.</p>',31)])])}const m=t(n,[["render",s]]);export{p as __pageData,m as default};
